import 'dart:ui' as ui;
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';

void main() => runApp(const MaterialApp(home: EngineInfoPage()));

class EngineInfoPage extends StatelessWidget {
  const EngineInfoPage({super.key});

  @override
  Widget build(BuildContext context) {
    // Info Flutter exposes about the engine + platform:
    final view = View.of(context);
    final display = view.display;

    final info = [
      'Compilation mode',
      kDebugMode ? 'debug (JIT)' : kProfileMode ? 'profile (AOT)' : 'release (AOT)',
      'Impeller enabled', view.platformDispatcher.implicitView == null ? 'unknown' : 'yes (default on modern iOS/Android)',
      'Platform', defaultTargetPlatform.name,
      'Physical resolution', '${display.size.width.toInt()} x ${display.size.height.toInt()}',
      'Device pixel ratio', display.devicePixelRatio.toStringAsFixed(2),
      'Refresh rate', '${display.refreshRate.toStringAsFixed(0)} Hz',
      'Frame budget', '${(1000 / display.refreshRate).toStringAsFixed(1)} ms',
      'Text scale', view.platformDispatcher.textScaleFactor.toStringAsFixed(2),
      'Locale', view.platformDispatcher.locale.toLanguageTag(),
    ];

    return Scaffold(
      appBar: AppBar(title: const Text('Flutter engine info')),
      body: ListView.builder(
        itemCount: info.length ~/ 2,
        itemBuilder: (_, i) => ListTile(
          title: Text(info[i * 2]),
          trailing: Text(info[i * 2 + 1]),
        ),
      ),
    );
  }
}

// Displays: compilation mode, target platform, resolution, DPI, refresh
// rate (60/90/120 Hz), text scale, locale. All exposed by the engine.
// Great sanity check that Impeller / your target platform look right.
